def _minvol(model, v):
    return sum(model.qmax[vv, s] * model.pl[vv, s] for (vv, s) in model.vs if vv == v) >= 10000
model.minvol = Constraint(model.v, rule=_minvol)

def _maxvol(model, v):
    return sum(model.qmax[vv, s] * model.pl[vv, s] for (vv, s) in model.vs if vv == v) <= 120000
model.maxvol = Constraint(model.v, rule=_maxvol)
